import { ChatOpenAI } from '@langchain/openai';
import { AgentExecutor } from 'langchain/agents';
import { createReactAgent } from '@langchain/core/agents';

class VoiceAgent {
  constructor() {
    this.model = new ChatOpenAI({ model: 'gpt-4o-mini', streaming: true });
    this.agent = createReactAgent({ llm: this.model, tools });
    this.executor = AgentExecutor.fromAgentAndTools({
      agent: this.agent,
      tools,
      maxIterations: 3
    });
  }

  async processAudio(transcript: string): Promise<string> {
    const start = performance.now();
    const result = await this.executor.invoke({ input: transcript });
    const latency = performance.now() - start;

    if (latency > 800) {
      throw new Error(`Latency violation: ${latency}ms`);
    }

    return result.output;
  }
}

